const conversation = $json.data.message.conversation;

// Check if REF exists
const refMatch = conversation.match(/REF=(\w+)/);
const titleMatch = conversation.match(/interested in:\s*(.+?)(?=\nREF=)/s);

if (refMatch) {
  // First message with REF - extract it
  return {
    json: {
      ...($json),
      extractedRef: refMatch[1],
      extractedTitle: titleMatch ? titleMatch[1].trim() : null,
      isFirstMessage: true,
      originalMessage: conversation
    }
  };
} else {
  // Follow-up message without REF
  return {
    json: {
      ...($json),
      extractedRef: null,
      extractedTitle: null,
      isFirstMessage: false,
      originalMessage: conversation
    }
  };
}
